// Yahoo spark flat format: { "SPY": { close, high, low, volume, timestamp, previousClose, chartPreviousClose }, ... }
const tickers = $('EOD Tickers').first().json.tickers;
const data    = $input.first().json;  // combined flat object from Combine Batches

const r = n => (n !== null && n !== undefined && !isNaN(n))
  ? Math.round(n * 100) / 100 : null;

return Object.entries(data).map(([sym, d]) => {
  const ticker = tickers.find(t => t.symbol === sym)
               || { symbol: sym, label: sym, category: 'Unknown' };

  const closes  = (d.close  || []);
  const highs   = (d.high   || []);
  const lows    = (d.low    || []);
  const volumes = (d.volume || []);

  // Last valid close
  const validCloses = closes.filter(c => c != null);
  const lastClose   = r(validCloses[validCloses.length - 1]);

  // Previous close: prefer chartPreviousClose (most reliable for EOD)
  const prevClose = r(d.chartPreviousClose || d.previousClose || validCloses[validCloses.length - 2]);

  const change        = (lastClose != null && prevClose != null) ? r(lastClose - prevClose) : null;
  const percentChange = (lastClose != null && prevClose != null && prevClose !== 0)
    ? r(((lastClose - prevClose) / Math.abs(prevClose)) * 100) : null;

  // Today's high/low from last bar
  const lastHigh = r(highs.filter(h => h != null).slice(-1)[0] ?? lastClose);
  const lastLow  = r(lows.filter(l => l != null).slice(-1)[0]  ?? lastClose);

  const dayRangePct = (lastHigh != null && lastLow != null && prevClose != null && prevClose !== 0)
    ? r(((lastHigh - lastLow) / Math.abs(prevClose)) * 100) : null;

  // Volume ratio: today vs average of prior days
  const validVols = volumes.filter(v => v != null && v > 0);
  const lastVol   = validVols[validVols.length - 1] || 0;
  const priorVols = validVols.slice(0, -1);
  const avgVol    = priorVols.length > 0
    ? Math.round(priorVols.reduce((a, b) => a + b, 0) / priorVols.length) : 0;
  const volumeRatio = avgVol > 0 ? r(lastVol / avgVol) : null;

  return { json: {
    symbol:       sym,
    label:        ticker.label,
    category:     ticker.category,
    price:        lastClose,
    prevClose,
    change,
    percentChange,
    high:         lastHigh,
    low:          lastLow,
    dayRangePct,
    volume:       lastVol,
    avgVolume:    avgVol,
    volumeRatio,
  }};
});

const data    = $json.marketData;
const pmData  = $json.pmRow || null;

const today = new Date().toLocaleDateString('en-US', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

const r    = n => (n !== null && n !== undefined && !isNaN(n)) ? Math.round(n * 100) / 100 : null;
const sign = n => (n !== null && n >= 0) ? "+" : "";
const pct  = n => n !== null ? sign(n) + n + "%" : "N/A";
const pad  = (s, len) => String(s).padEnd(len);
const arr  = n => (n !== null && n > 0.05) ? "^" : (n !== null && n < -0.05) ? "v" : "-";

const OFFENSIVE = ["XLK","XLY","XLF","XLI","XLB","XLE"];
const DEFENSIVE = ["XLU","XLRE","XLP","XLV","XLC"];

// -- Assets --
const find  = sym => data.find(d => d.symbol === sym);
const es    = find("ES=F");
const nq    = find("NQ=F");
const ym    = find("YM=F");
const rty   = find("RTY=F");
const spy   = find("SPY");
const qqq   = find("QQQ");
const iwm   = find("IWM");
const dia   = find("DIA");
const rsp   = find("RSP");
const vix   = find("^VIX");
const tnx   = find("^TNX");
const tlt   = find("TLT");
const hyg   = find("HYG");
const dxy   = find("DX-Y.NYB");
const gold  = find("GC=F");
const oil   = find("CL=F");
const btc   = find("BTC-USD");
const eth   = find("ETH-USD");

const sectors       = data.filter(d => d.category === "Sector");
const sectorsSorted = [...sectors].sort((a, b) => (b.percentChange || 0) - (a.percentChange || 0));
const sectorBySymbol = {};
sectors.forEach(s => { sectorBySymbol[s.symbol] = s; });

// -- Breadth check at close --
const breadthDiff = (rsp?.percentChange != null && spy?.percentChange != null)
  ? r(rsp.percentChange - spy.percentChange) : null;
const breadthClose = breadthDiff !== null
  ? breadthDiff >= 0.2  ? "BROAD +" + breadthDiff + "% RSP lead"
  : breadthDiff <= -0.2 ? "NARROW " + breadthDiff + "% RSP lag"
  : "NEUTRAL"
  : "N/A";

// -- Credit check at close --
const creditClose = (hyg?.percentChange != null && tlt?.percentChange != null)
  ? hyg.percentChange < -0.5 && tlt.percentChange > 0.3 ? "WIDENING (!)"
  : hyg.percentChange > 0.3  && tlt.percentChange < 0   ? "COMPRESSING (ok)"
  : "NEUTRAL"
  : "N/A";

// -- Rotation at close --
const top5 = sectorsSorted.slice(0, 5).map(s => s.symbol);
const rotationScore = top5.reduce((sc, sym) => {
  if (OFFENSIVE.includes(sym)) return sc + 1;
  if (DEFENSIVE.includes(sym)) return sc - 1;
  return sc;
}, 0);
const rotationBias = rotationScore >= 2 ? "OFFENSIVE" : rotationScore <= -2 ? "DEFENSIVE" : "MIXED";

// -- Unusual volume (1.5x, ETFs only: Equity Index / Leadership / Sector) --
// Only track ETFs where Yahoo volume data is reliable
const VOL_CATEGORIES = new Set(["Equity Index", "Leadership", "Sector"]);
const unusualMovers = data
  .filter(d =>
    d.volumeRatio != null &&
    d.volumeRatio > 1.5 &&
    d.avgVolume > 500000 &&
    VOL_CATEGORIES.has(d.category)
  )
  .sort((a, b) => (b.volumeRatio || 0) - (a.volumeRatio || 0))
  .slice(0, 6);

// -- Pre-market comparison block --
let pmCompare = "";
if (pmData && pmData.RiskVerdict) {
  const pmVerdict  = pmData.RiskVerdict  || "N/A";
  const pmFocus    = pmData.FocusSectors || "N/A";
  const pmTop3     = pmData.Top3Sectors  || "N/A";
  const pmBot3     = pmData.Bot3Sectors  || "N/A";

  const focusSyms  = pmFocus.split(",").map(s => s.trim());
  const actualTop  = sectorsSorted[0]?.symbol;
  const focusHit   = focusSyms.includes(actualTop);
  const focusResult = focusHit
    ? "[OK] Focus sector **" + actualTop + "** was day leader"
    : "[X] Focus (" + pmFocus + ") -- actual leader: **" + actualTop + "**";

  const spyChg = spy?.percentChange || 0;
  const verdictAligned =
    (pmVerdict.includes("RISK-ON")  && spyChg > 0) ? "[OK] Verdict confirmed" :
    (pmVerdict.includes("RISK-OFF") && spyChg < 0) ? "[OK] Verdict confirmed" :
    (pmVerdict === "MIXED")                          ? "[~] Mixed -- no clear signal" :
                                                       "[X] Verdict not confirmed";

  pmCompare = [
    "**:repeat: Pre-Market vs Close**",
    "```",
    "AM verdict   " + pmVerdict + " -> " + verdictAligned,
    "AM focus     " + pmFocus,
    focusResult,
    "AM top 3     " + pmTop3,
    "AM bottom 3  " + pmBot3,
    "```",
    ""
  ].join("\n");
} else {
  pmCompare = "**:repeat: Pre-Market vs Close**\n_No pre-market data found for today_\n\n";
}

// -- INDEX TABLE with day range --
const idxRows = [spy, qqq, iwm, dia].filter(Boolean).map(d =>
  arr(d.percentChange) + " " + pad(d.symbol, 6) +
  pad(d.price != null ? "$" + r(d.price) : "N/A", 10) +
  pad(pct(r(d.percentChange)), 9) +
  (d.dayRangePct != null ? "range " + r(d.dayRangePct) + "%" : "")
);
const vixRow = arr(vix?.percentChange) + " " + pad("VIX", 6) +
  pad(vix?.price != null ? String(r(vix.price)) : "N/A", 10) +
  pct(r(vix?.percentChange));
const indexTable = "```\n  TICKER  CLOSE     CHG      DAY RANGE\n" + idxRows.join("\n") + "\n" + vixRow + "\n```";

// -- SECTOR TABLE --
const sectorRows = sectorsSorted.map(s =>
  arr(s.percentChange) + " " + pad(s.label, 24) +
  pct(r(s.percentChange))
);
const sectorTable = "```\n  SECTOR                   CHG\n" + sectorRows.join("\n") + "\n```";

// -- MACRO TABLE --
const macroRows = [
  { d: gold, label: "Gold  " },
  { d: oil,  label: "Oil   " },
  { d: btc,  label: "BTC   " },
  { d: eth,  label: "ETH   " },
  { d: tnx,  label: "10Y   " },
  { d: dxy,  label: "DXY   " },
  { d: hyg,  label: "Credit" },
].filter(x => x.d && x.d.price != null).map(x =>
  arr(x.d.percentChange) + " " + x.label + " " +
  pad("$" + r(x.d.price), 10) +
  pct(r(x.d.percentChange))
);
const macroTable = "```\n  ASSET   CLOSE     CHG\n" + macroRows.join("\n") + "\n```";

// -- UNUSUAL VOLUME BLOCK --
const volBlock = unusualMovers.length > 0
  ? unusualMovers.map(d =>
      ":fire: " + pad(d.symbol, 7) +
      pad(pct(r(d.percentChange)), 9) +
      r(d.volumeRatio) + "x avg vol"
    ).join("\n")
  : "_No unusual volume today (threshold: 1.5x avg)_";

// -- ROTATION SUMMARY --
const rotationEmoji = rotationBias === "OFFENSIVE" ? ":chart_with_upwards_trend:" : rotationBias === "DEFENSIVE" ? ":shield:" : ":scales:";
const top3   = sectorsSorted.slice(0, 3).map(s => s.label + " (" + pct(r(s.percentChange)) + ")").join("  ");
const bot3   = sectorsSorted.slice(-3).map(s => s.label + " (" + pct(r(s.percentChange)) + ")").join("  ");

// -- FULL MESSAGE --
const message = [
  ":calendar: **" + today + "**",
  "**END OF DAY RECAP**",
  "=========================",
  "",
  pmCompare,
  ":bar_chart: **Index Close**",
  indexTable,
  "",
  ":thermometer: **Breadth & Credit at Close**",
  "```",
  "Breadth  " + breadthClose,
  "Credit   " + creditClose,
  "```",
  "",
  ":map: **Sector Close**",
  rotationEmoji + " Rotation: **" + rotationBias + "**",
  "Leaders:  " + top3,
  "Laggards: " + bot3,
  sectorTable,
  "",
  ":fire: **Unusual Volume** _(1.5x avg, ETFs only)_",
  volBlock,
  "",
  ":earth_africa: **Macro Close**",
  macroTable,
].join("\n");

// -- SAVE ROW --
const sectorRanking = sectorsSorted
  .map((s, i) => (i+1) + ". " + s.symbol + "(" + (s.percentChange >= 0 ? "+" : "") + r(s.percentChange) + "%)")
  .join(", ");
const top3Sectors = sectorsSorted.slice(0, 3)
  .map(s => s.symbol + "(" + pct(r(s.percentChange)) + ")").join(", ");
const bot3Sectors = sectorsSorted.slice(-3)
  .map(s => s.symbol + "(" + pct(r(s.percentChange)) + ")").join(", ");

const saveRow = {
  Date:              today,
  Timestamp:         new Date().toISOString(),
  Type:              "EOD",
  SPY_Close:         spy?.price,
  SPY_Change:        spy?.percentChange,
  QQQ_Change:        qqq?.percentChange,
  IWM_Change:        iwm?.percentChange,
  DIA_Change:        dia?.percentChange,
  VIX_Close:         vix?.price,
  VIX_Change:        vix?.percentChange,
  BreadthClose:      breadthClose,
  CreditClose:       creditClose,
  Yield10Y:          tnx?.price,
  Yield10Y_Change:   tnx?.percentChange,
  Gold_Change:       gold?.percentChange,
  Oil_Change:        oil?.percentChange,
  BTC_Change:        btc?.percentChange,
  DXY_Change:        dxy?.percentChange,
  RotationBias:      rotationBias,
  RotationScore:     rotationScore,
  SectorRanking:     sectorRanking,
  Top3Sectors:       top3Sectors,
  Bot3Sectors:       bot3Sectors,
  XLK_Change:        sectorBySymbol["XLK"]?.percentChange,
  XLY_Change:        sectorBySymbol["XLY"]?.percentChange,
  XLF_Change:        sectorBySymbol["XLF"]?.percentChange,
  XLI_Change:        sectorBySymbol["XLI"]?.percentChange,
  XLB_Change:        sectorBySymbol["XLB"]?.percentChange,
  XLE_Change:        sectorBySymbol["XLE"]?.percentChange,
  XLV_Change:        sectorBySymbol["XLV"]?.percentChange,
  XLU_Change:        sectorBySymbol["XLU"]?.percentChange,
  XLRE_Change:       sectorBySymbol["XLRE"]?.percentChange,
  XLP_Change:        sectorBySymbol["XLP"]?.percentChange,
  XLC_Change:        sectorBySymbol["XLC"]?.percentChange,
  UnusualMovers:     unusualMovers.map(d => d.symbol + "(" + r(d.volumeRatio) + "x)").join(", "),
  PM_Verdict:        pmData?.RiskVerdict  || "",
  PM_FocusSectors:   pmData?.FocusSectors || "",
  PM_RotationBias:   pmData?.RotationBias || "",
};

return [{ json: { message, saveRow } }];

// Pull today's pre-market row from Google Sheets
// Passes it along as pmRow for the Compute node to use
const rows = $input.all().map(r => r.json);
const todayStr = new Date().toLocaleDateString('en-US', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});
// Find today's pre-market row
const pmRow = rows.find(r => r.Date === todayStr && (!r.Type || r.Type === 'PRE-MARKET')) || null;
return [{ json: { pmRow } }];

// Stop execution if today is not a NYSE trading day
const now = new Date();

// Weekend check (0=Sun, 6=Sat)
const dow = now.getUTCDay();
if (dow === 0 || dow === 6) return [];

const year  = now.getUTCFullYear();
const month = String(now.getUTCMonth() + 1).padStart(2, '0');
const date  = String(now.getUTCDate()).padStart(2, '0');
const today = year + '-' + month + '-' + date;

function nthWeekday(y, m, wd, n) {
  const d = new Date(Date.UTC(y, m, 1));
  let count = 0;
  while (d.getUTCMonth() === m) {
    if (d.getUTCDay() === wd && ++count === n) return d;
    d.setUTCDate(d.getUTCDate() + 1);
  }
}
function lastWeekday(y, m, wd) {
  const d = new Date(Date.UTC(y, m + 1, 0));
  while (d.getUTCDay() !== wd) d.setUTCDate(d.getUTCDate() - 1);
  return d;
}
function observed(y, m, day) {
  const d  = new Date(Date.UTC(y, m, day));
  const wd = d.getUTCDay();
  if (wd === 6) d.setUTCDate(day - 1);
  if (wd === 0) d.setUTCDate(day + 1);
  return d;
}
function fmt(d) {
  return d.getUTCFullYear() + '-' +
    String(d.getUTCMonth() + 1).padStart(2, '0') + '-' +
    String(d.getUTCDate()).padStart(2, '0');
}
function goodFriday(y) {
  const a=y%19,b=Math.floor(y/100),c=y%100,d=Math.floor(b/4),e=b%4;
  const f=Math.floor((b+8)/25),g=Math.floor((b-f+1)/3);
  const h=(19*a+b-d-g+15)%30,i=Math.floor(c/4),k=c%4;
  const l=(32+2*e+2*i-h-k)%7,m=Math.floor((a+11*h+22*l)/451);
  const mo=Math.floor((h+l-7*m+114)/31),da=((h+l-7*m+114)%31)+1;
  const easter=new Date(Date.UTC(y,mo-1,da));
  easter.setUTCDate(easter.getUTCDate()-2);
  return easter;
}

const holidays = new Set([
  fmt(observed(year, 0,  1)),
  fmt(nthWeekday(year, 0,  1, 3)),
  fmt(nthWeekday(year, 1,  1, 3)),
  fmt(goodFriday(year)),
  fmt(lastWeekday(year, 4,  1)),
  fmt(observed(year, 5,  19)),
  fmt(observed(year, 6,  4)),
  fmt(nthWeekday(year, 8,  1, 1)),
  fmt(nthWeekday(year, 10, 4, 4)),
  fmt(observed(year, 11, 25)),
]);

if (holidays.has(today)) return [];

return [{ json: {} }];

// Split symbols into batches of <=20 (Yahoo spark API limit)
const allSymbols = $json.symbols.split(',');
const BATCH_SIZE = 20;
const output = [];
for (let i = 0; i < allSymbols.length; i += BATCH_SIZE) {
  output.push({ json: { symbols: allSymbols.slice(i, i + BATCH_SIZE).join(',') } });
}
return output;

// Yahoo spark returns flat object { ticker: { close, timestamp, ... } }
// Merge all batch responses into one flat object
const combined = {};
for (const item of $input.all()) {
  Object.assign(combined, item.json);
}
return [{ json: combined }];

// Split message into <=1950 char chunks at newline boundaries
// (Discord hard limit is 2000; we use 1950 for safety margin)
const text = $json.text || $json.message || '';
const MAX  = 1950;

if (text.length <= MAX) {
  return [{ json: { text } }];
}

const lines  = text.split('\n');
const chunks = [];
let current  = '';

for (const line of lines) {
  const candidate = current ? current + '\n' + line : line;
  if (candidate.length <= MAX) {
    current = candidate;
  } else {
    if (current) chunks.push(current);
    // Hard-split any single line that is itself too long
    if (line.length > MAX) {
      for (let i = 0; i < line.length; i += MAX) {
        chunks.push(line.slice(i, i + MAX));
      }
      current = '';
    } else {
      current = line;
    }
  }
}
if (current) chunks.push(current);

return chunks.map(chunk => ({ json: { text: chunk } }));
